export function generateLicenseMD(config: any): string {
  let md = '# License Compliance Checker\n\n';
  md += '## Features\n\n';
  md += '- Cross-ecosystem license detection\n';
  md += '- Policy-based compliance checking\n';
  md += '- Automatic violation detection\n';
  md += '- License categorization (permissive, copyleft, proprietary)\n';
  md += '- Support for: npm, pip, cargo, maven, gradle, composer\n\n';
  md += '## Usage\n\n';
  md += '### TypeScript/JavaScript\n';
  md += '```typescript\n';
  md += 'import checker from \'./license-compliance\';\n\n';
  md += '// Check compliance\n';
  md += 'const results = await checker.checkCompliance();\n\n';
  md += '// Generate report\n';
  md += 'await checker.generateReport(results);\n\n';
  md += '// Fix violations\n';
  md += 'await checker.fixViolations(results);\n';
  md += '```\n\n';
  md += '### Python\n';
  md += '```python\n';
  md += 'from license_compliance import checker\n\n';
  md += '# Check compliance\n';
  md += 'results = await checker.check_compliance()\n\n';
  md += '# Generate report\n';
  md += 'await checker.generate_report(results)\n';
  md += '```\n\n';
  return md;
}

