  code += '        md += \'\\n\';\n';
  code += '      }\n';
  code += '    }\n\n';
  code += '    return md;\n';
  code += '  }\n\n';
  code += '  private getDefaultPolicy(): CompliancePolicy {\n';
  code += '    return {\n';
